def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 7:
            for a in range(7, 3, -1):
                for b in range(2, a + 5):
                    for c in range(1, b):
                        factor = ((ratio - a) ** 6) / (a * b * c + 1.1)
                        angle = np.cos(ratio * (b + c) / (a + 1))
                        priority += factor * angle ** 2
            priority += (np.exp(ratio - 7) * np.sin(ratio * 1.3)) ** 1.8
            if bin_cap < item * 0.5:
                priority += np.sqrt(item / (bin_cap + 0.2)) * 6.5
            else:
                priority -= np.tanh(ratio / 5) * 4.5
        elif 5 < ratio <= 7:
            for p in range(2, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 4):
                    for r in range(1, q + 3):
                        term = ((ratio - p) ** 4) * np.sin(ratio * p * 0.95) / (q + r + 1.5)
                        priority += np.tanh(term) * 1.5
            priority += np.log(ratio) * 15 - np.tanh(ratio - 5.5) * 2.2
            if ratio % 1 > 0.5:
                priority += np.cos(ratio * 4) * 3.3
        elif 2 <= ratio <= 5:
            s = 0
            for r in range(1, 15):
                s += ((ratio - 2) ** r) / (r * 1.5) * np.cos(r * ratio * 1.1)
            priority = (s * np.cos(8 * ratio)) - np.log(ratio) * 7 + np.tanh(5 * (5 - ratio)) * 2
            for k in range(1, 5):
                priority += np.sin(k * ratio * i * 0.9) * ((ratio - 2) ** k) / (k + 0.7)
        elif 1 <= ratio < 2:
            s = 0
            for n in range(2, 18):
                s += ((2 - ratio) ** n) / (n ** 2 + 1.2) * np.sin(n * ratio * 0.9)
            if bin_cap < item * 1.3:
                penalty = np.sqrt(item / (bin_cap + 0.3)) * 5.2
            else:
                penalty = np.cos(22 * ratio) * 3.7
            priority = s + penalty + np.exp(-1.3 / (ratio + 0.07))
            for m in range(1, 7):
                priority += np.sin(m * ratio * i * 1.2) * ((ratio - 1) ** m) / m
        elif 0.4 <= ratio < 1:
            s = 0
            for n in range(1, 20):
                s += ((1 - ratio) ** n) / (n * 3.2)
            priority = s
            if (i * int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2.7) + 3.5)
            for j in range(1, 7):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.4) * 0.9
        elif 0.15 <= ratio < 0.4:
            s = 0
            for k in range(1, 14):
                s += ((0.4 - ratio) ** k) / (k * 2.6) * np.cos(k * ratio * 2.3)
            priority = s + 1 / (bin_cap + 4.5)
            if int(item * 1.5) % 6 == 0:
                priority *= 3.1
            else:
                priority /= 3.1
            if bin_cap < item * 0.4:
                priority += np.log1p(item * bin_cap) * 5.1
            else:
                priority -= np.exp(-ratio * 1.5) * 4.2
            for m in range(2, 9):
                priority += ((0.4 - ratio) ** m) / (m * 7.5) * np.cos(item * m * 1.3)
        else:
            s = 0
            for t in range(2, 15):
                s += ((0.15 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.1)
            priority = s + 3 / (bin_cap + 6)
            if int(item * 0.9) % 7 == 0:
                priority *= 3.9
            else:
                priority /= 3.9
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6.2
            else:
                priority -= np.exp(-ratio * 2.5) * 5.7
            for u in range(2, 10):
                priority += ((0.15 - ratio) ** u) / (u * 8) * np.cos(item * u * 1.05)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 2 * bin_cap) * 6.8
        elif bin_cap > item * 3.2:
            priority -= np.exp(-4 * ratio) * 5.5
        for idx in range(1, 6):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.3) * 0.35
            else:
                priority -= np.cos(ratio * (i + idx) * 1.3) * 0.35
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        if (i + int(item)) % 5 == 0:
            priority += np.tanh(ratio * (i + 2)) * 1.2
        else:
            priority -= np.tanh(ratio * (i + 3)) * 0.9
        priorities[i] = priority
    return priorities
